111→func initDatabase() error {
112→	if config.Keys.DbConfig != nil {
113→		cfg := repository.DefaultConfig()
114→		dc := config.Keys.DbConfig
115→		if dc.CacheSizeMB > 0 {
116→			cfg.DbCacheSizeMB = dc.CacheSizeMB
117→		}
118→		if dc.SoftHeapLimitMB > 0 {
119→			cfg.DbSoftHeapLimitMB = dc.SoftHeapLimitMB
120→		}
121→		if dc.MaxOpenConnections > 0 {
122→			cfg.MaxOpenConnections = dc.MaxOpenConnections
123→		}
124→		if dc.MaxIdleConnections > 0 {
125→			cfg.MaxIdleConnections = dc.MaxIdleConnections
126→		}
127→		if dc.ConnectionMaxIdleTimeMins > 0 {
128→			cfg.ConnectionMaxIdleTime = time.Duration(dc.ConnectionMaxIdleTimeMins) * time.Minute
129→		}
130→		if dc.BusyTimeoutMs > 0 {
131→			cfg.BusyTimeoutMs = dc.BusyTimeoutMs
132→		}
133→		repository.SetConfig(cfg)
134→	}
135→	repository.Connect(config.Keys.DB)
136→	return nil
137→}
