139→func handleDatabaseCommands() error {
140→	if flagMigrateDB {
141→		err := repository.MigrateDB(config.Keys.DB)
142→		if err != nil {
143→			return fmt.Errorf("migrating database to version %d: %w", repository.Version, err)
144→		}
145→		cclog.Exitf("MigrateDB Success: Migrated SQLite database at '%s' to version %d.\n",
146→			config.Keys.DB, repository.Version)
147→	}
148→
149→	if flagRevertDB {
150→		err := repository.RevertDB(config.Keys.DB)
151→		if err != nil {
152→			return fmt.Errorf("reverting database to version %d: %w", repository.Version-1, err)
153→		}
154→		cclog.Exitf("RevertDB Success: Reverted SQLite database at '%s' to version %d.\n",
155→			config.Keys.DB, repository.Version-1)
156→	}
157→
158→	if flagForceDB {
159→		err := repository.ForceDB(config.Keys.DB)
160→		if err != nil {
161→			return fmt.Errorf("forcing database to version %d: %w", repository.Version, err)
162→		}
163→		cclog.Exitf("ForceDB Success: Forced SQLite database at '%s' to version %d.\n",
164→			config.Keys.DB, repository.Version)
165→	}
166→
167→	return nil
168→}
