268→func generateJWT(authHandle *auth.Authentication, username string) error {
269→	ur := repository.GetUserRepository()
270→	user, err := ur.GetUser(username)
271→	if err != nil {
272→		return fmt.Errorf("getting user '%s': %w", username, err)
273→	}
274→
275→	if !user.HasRole(schema.RoleAPI) {
276→		cclog.Warnf("JWT: User '%s' does not have the role 'api'. REST API endpoints will return error!\n", user.Username)
277→	}
278→
279→	jwt, err := authHandle.JwtAuth.ProvideJWT(user)
280→	if err != nil {
281→		return fmt.Errorf("generating JWT for user '%s': %w", user.Username, err)
282→	}
283→
284→	cclog.Printf("JWT: Successfully generated JWT for user '%s': %s\n", user.Username, jwt)
285→	return nil
286→}
