465→func run() error {
466→	cliInit()
467→
468→	if flagVersion {
469→		printVersion()
470→		return nil
471→	}
472→
473→	// Initialize logger
474→	cclog.Init(flagLogLevel, flagLogDateTime)
475→
476→	// Handle init flag
477→	if flagInit {
478→		initEnv()
479→		cclog.Exit("Successfully setup environment!\n" +
480→			"Please review config.json and .env and adjust it to your needs.\n" +
481→			"Add your job-archive at ./var/job-archive.")
482→	}
483→
484→	// Initialize gops agent
485→	if err := initGops(); err != nil {
486→		return err
487→	}
488→
489→	// Initialize subsystems in dependency order:
490→	// 1. Load environment variables from .env file (contains sensitive configuration)
491→	// 2. Load configuration from config.json (may reference environment variables)
492→	// 3. Handle database migration commands if requested
493→	// 4. Initialize database connection (requires config for connection string)
494→	// 5. Handle user commands if requested (requires database and authentication config)
495→	// 6. Initialize subsystems like archive and metrics (require config and database)
496→
497→	// Load environment and configuration
498→	if err := loadEnvironment(); err != nil {
499→		return err
500→	}
501→
502→	if err := initConfiguration(); err != nil {
503→		return err
504→	}
505→
506→	// Handle database migration (migrate, revert, force)
507→	if err := handleDatabaseCommands(); err != nil {
508→		return err
509→	}
510→
511→	// Initialize database
512→	if err := initDatabase(); err != nil {
513→		return err
514→	}
515→
516→	// Optimize database if requested
517→	if flagOptimizeDB {
518→		db := repository.GetConnection()
519→		cclog.Print("Running VACUUM to reclaim space and defragment database...")
520→		if _, err := db.DB.Exec("VACUUM"); err != nil {
521→			return fmt.Errorf("VACUUM failed: %w", err)
522→		}
523→		cclog.Print("Running ANALYZE to update query planner statistics...")
524→		if _, err := db.DB.Exec("ANALYZE"); err != nil {
525→			return fmt.Errorf("ANALYZE failed: %w", err)
526→		}
527→		cclog.Exitf("OptimizeDB Success: Database '%s' optimized (VACUUM + ANALYZE).\n", config.Keys.DB)
528→	}
529→
530→	// Handle user commands (add, delete, sync, JWT)
531→	if err := handleUserCommands(); err != nil {
532→		return err
533→	}
534→
535→	// Initialize subsystems (archive, metrics, taggers)
536→	if err := initSubsystems(); err != nil {
537→		return err
538→	}
539→
540→	// Handle checkpoint cleanup
541→	if flagCleanupCheckpoints {
542→		mscfg := ccconf.GetPackageConfig("metric-store")
543→		if mscfg == nil {
544→			return fmt.Errorf("metric-store configuration required for checkpoint cleanup")
545→		}
546→		if err := json.Unmarshal(mscfg, &metricstore.Keys); err != nil {
547→			return fmt.Errorf("decoding metric-store config: %w", err)
548→		}
549→		if metricstore.Keys.NumWorkers <= 0 {
550→			metricstore.Keys.NumWorkers = min(goruntime.NumCPU()/2+1, metricstore.DefaultMaxWorkers)
551→		}
552→
553→		d, err := time.ParseDuration(metricstore.Keys.RetentionInMemory)
554→		if err != nil {
555→			return fmt.Errorf("parsing retention-in-memory: %w", err)
556→		}
557→		from := time.Now().Add(-d)
558→		deleteMode := metricstore.Keys.Cleanup == nil || metricstore.Keys.Cleanup.Mode != "archive"
559→		cleanupDir := ""
560→		if !deleteMode {
561→			cleanupDir = metricstore.Keys.Cleanup.RootDir
562→		}
563→
564→		cclog.Infof("Cleaning up checkpoints older than %s...", from.Format(time.RFC3339))
565→		n, err := metricstore.CleanupCheckpoints(
566→			metricstore.Keys.Checkpoints.RootDir, cleanupDir, from.Unix(), deleteMode)
567→		if err != nil {
568→			return fmt.Errorf("checkpoint cleanup: %w", err)
569→		}
570→		if deleteMode {
571→			cclog.Exitf("Cleanup done: %d checkpoint files deleted.", n)
572→		} else {
573→			cclog.Exitf("Cleanup done: %d checkpoint files archived to parquet.", n)
574→		}
575→	}
576→
577→	// Exit if start server is not requested
578→	if !flagServer {
579→		cclog.Exit("No errors, server flag not set. Exiting cc-backend.")
580→	}
581→
582→	// Run server with context
583→	ctx, cancel := context.WithCancel(context.Background())
584→	defer cancel()
585→
586→	return runServer(ctx)
587→}
