181→// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
182→//
183→// Metrics at root and cluster levels are skipped. One file per host is created.
184→// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
185→// at a time, allowing concurrent writes/reads to other hosts.
186→//
187→// Returns the number of checkpoint files created and any errors encountered.
188→func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
189→	// Pre-calculate capacity by counting cluster/host pairs
190→	m.root.lock.RLock()
191→	totalHosts := 0
192→	for _, l1 := range m.root.children {
193→		l1.lock.RLock()
194→		totalHosts += len(l1.children)
195→		l1.lock.RUnlock()
196→	}
197→	m.root.lock.RUnlock()
198→
199→	levels := make([]*Level, 0, totalHosts)
200→	selectors := make([][]string, 0, totalHosts)
201→
202→	m.root.lock.RLock()
203→	for sel1, l1 := range m.root.children {
204→		l1.lock.RLock()
205→		for sel2, l2 := range l1.children {
206→			levels = append(levels, l2)
207→			selectors = append(selectors, []string{sel1, sel2})
208→		}
209→		l1.lock.RUnlock()
210→	}
211→	m.root.lock.RUnlock()
212→
213→	type workItem struct {
214→		level    *Level
215→		dir      string
216→		selector []string
217→	}
218→
219→	n, errs := int32(0), int32(0)
220→
221→	var wg sync.WaitGroup
222→	wg.Add(Keys.NumWorkers)
223→	work := make(chan workItem, Keys.NumWorkers*2)
224→	for worker := 0; worker < Keys.NumWorkers; worker++ {
225→		go func() {
226→			defer wg.Done()
227→
228→			for workItem := range work {
229→				if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
230→					if err == ErrNoNewArchiveData {
231→						continue
232→					}
233→
234→					cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
235→					atomic.AddInt32(&errs, 1)
236→				} else {
237→					atomic.AddInt32(&n, 1)
238→				}
239→			}
240→		}()
241→	}
242→
243→	for i := 0; i < len(levels); i++ {
244→		dir := path.Join(dir, path.Join(selectors[i]...))
245→		work <- workItem{
246→			level:    levels[i],
247→			dir:      dir,
248→			selector: selectors[i],
249→		}
250→	}
251→
252→	close(work)
253→	wg.Wait()
254→
255→	if errs > 0 {
256→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
257→	}
258→	return int(n), nil
259→}
