361→// enqueueCheckpointHosts traverses checkpoint directory and enqueues cluster/host pairs.
362→// Returns error if directory structure is invalid.
363→func enqueueCheckpointHosts(dir string, work chan<- [2]string) error {
364→	clustersDir, err := os.ReadDir(dir)
365→	if err != nil {
366→		return err
367→	}
368→
369→	for _, clusterDir := range clustersDir {
370→		if !clusterDir.IsDir() {
371→			return errors.New("[METRICSTORE]> expected only directories at first level of checkpoints/ directory")
372→		}
373→
374→		hostsDir, err := os.ReadDir(filepath.Join(dir, clusterDir.Name()))
375→		if err != nil {
376→			return err
377→		}
378→
379→		for _, hostDir := range hostsDir {
380→			if !hostDir.IsDir() {
381→				return errors.New("[METRICSTORE]> expected only directories at second level of checkpoints/ directory")
382→			}
383→
384→			work <- [2]string{clusterDir.Name(), hostDir.Name()}
385→		}
386→	}
387→
388→	return nil
389→}
