 83→var ErrNoNewArchiveData error = errors.New("all data already archived")
 84→
 85→// CleanupCheckpoints deletes or archives all checkpoint files older than `from`.
 86→// When archiving, consolidates all hosts per cluster into a single Parquet file.
 87→func CleanupCheckpoints(checkpointsDir, cleanupDir string, from int64, deleteInstead bool) (int, error) {
 88→	if deleteInstead {
 89→		return deleteCheckpoints(checkpointsDir, from)
 90→	}
 91→
 92→	return archiveCheckpoints(checkpointsDir, cleanupDir, from)
 93→}
 94→
 95→// deleteCheckpoints removes checkpoint files older than `from` across all clusters/hosts.
 96→func deleteCheckpoints(checkpointsDir string, from int64) (int, error) {
 97→	entries1, err := os.ReadDir(checkpointsDir)
 98→	if err != nil {
 99→		return 0, err
100→	}
101→
102→	type workItem struct {
103→		dir           string
104→		cluster, host string
105→	}
106→
107→	var wg sync.WaitGroup
108→	n, errs := int32(0), int32(0)
109→	work := make(chan workItem, Keys.NumWorkers)
110→
111→	wg.Add(Keys.NumWorkers)
112→	for worker := 0; worker < Keys.NumWorkers; worker++ {
113→		go func() {
114→			defer wg.Done()
115→			for item := range work {
116→				entries, err := os.ReadDir(item.dir)
117→				if err != nil {
118→					cclog.Errorf("error reading %s/%s: %s", item.cluster, item.host, err.Error())
119→					atomic.AddInt32(&errs, 1)
120→					continue
121→				}
122→
123→				files, err := findFiles(entries, from, false)
124→				if err != nil {
125→					cclog.Errorf("error finding files in %s/%s: %s", item.cluster, item.host, err.Error())
126→					atomic.AddInt32(&errs, 1)
127→					continue
128→				}
129→
130→				for _, checkpoint := range files {
131→					if err := os.Remove(filepath.Join(item.dir, checkpoint)); err != nil {
132→						cclog.Errorf("error deleting %s/%s/%s: %s", item.cluster, item.host, checkpoint, err.Error())
133→						atomic.AddInt32(&errs, 1)
134→					} else {
135→						atomic.AddInt32(&n, 1)
136→					}
137→				}
138→			}
139→		}()
140→	}
141→
142→	for _, de1 := range entries1 {
143→		entries2, e := os.ReadDir(filepath.Join(checkpointsDir, de1.Name()))
144→		if e != nil {
145→			err = e
146→			continue
147→		}
148→
