    msg := &WALMessage{
        MetricName: string(st.metricBuf),
        Cluster:    cluster,
        Node:       host,
        Selector:   append([]string{}, st.selector...),
        Value:      metric.Value,
        Timestamp:  time.Unix(),
    }

    // Option 1: Block on full (applies backpressure)
    if !SendWALMessageBlocking(msg, 1*time.Second) {
