    if walShardRotateChs == nil {
        return
    }

    dones := make([]chan struct{}, len(hostDirs))
    timeouts := make([]<-chan time.Time, len(hostDirs))

    for i, dir := range hostDirs {
        dones[i] = make(chan struct{})
        shard := walShardIndexFromDir(dir)

        // Use timeout to detect if goroutine is dead
        timeouts[i] = time.After(5 * time.Second)

        select {
        case walShardRotateChs[shard] <- walRotateReq{
            hostDir: dir,
            done:    dones[i],
        }:
            // Sent successfully
        case <-timeouts[i]:
            // Goroutine not responding, close the done channel ourselves
            close(dones[i])
        }
    }

    // Wait for responses with timeout
    for i, done := range dones {
        select {
        case <-done:
            // Normal completion
        case <-timeouts[i]:
            // Timeout, already handled above
            cclog.Warnf("[METRICSTORE]> Rotation timeout for host %d", i)
        }
    }
}
```

**Option C: Rotate before shutdown** (Best)

Don't call RotateWALFiles during shutdown at all. The final checkpoint doesn't need WAL rotation.

```go
