### Fix Strategy: Grace Period

```go
// In walCheckpoint.go WALStaging:
const ShutdownGracePeriod = 500 * time.Millisecond

for {
    select {
    case <-ctx.Done():
        // Don't exit immediately. Drain all buffered messages
        // that arrived before ctx.Done was signaled.

        // First, process any messages already in the channel
        for {
            select {
            case msg, ok := <-msgCh:
                if !ok {
                    // Channel closed, now safe to exit
                    flushDirty()
                    return
                }
                processMsg(msg)
            case req := <-rotateCh:
                processRotate(req)
            default:
                // No more messages immediately available
                // Give grace period for in-flight messages
                select {
                case msg, ok := <-msgCh:
                    if !ok {
                        flushDirty()
                        return
                    }
                    processMsg(msg)
                case <-time.After(ShutdownGracePeriod):
                    // Grace period expired, exit
                    flushDirty()
                    return
                }
            }
        }
    // ... other cases
    }
